var trimTrailingVowels = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    let i = s.length;
    while (i > 0 && vowels.has(s[i - 1])) {
        i -= 1;
    }
    return s.slice(0, i);
};
